import ArtGallery from "./components/ArtGallery/ArtGallery";
import Header from "./components/Header/Header";
import React from "react";
import Tutorial from "./components/Tutorial/Tutorial";

import { BrowserRouter as Router, Switch, Route } from "react-router-dom";

import "./App.scss";
import "./fonts/pkmn-game.ttf";

function App() {
   return (
      <div className="App">
         <Router>
            <Header />

            <main className="App-content">
               <Switch>
                  <Route path="/tutorial">
                     <Tutorial />
                  </Route>
                  <Route exact path="/">
                     <ArtGallery />
                  </Route>
                  <Route path="*">
                     <NoMatch />
                  </Route>
               </Switch>
            </main>
         </Router>
      </div>
   );
}

function Home() {
   return <h2>Home</h2>;
}

function NoMatch() {
   return <h2>404 not found</h2>;
}

function Users() {
   return <h2>Users</h2>;
}

export default App;
